func Test_UrlBatchMixedInputs(t *testing.T) {
	// extract_batch: mixed bytes and URL inputs share one output envelope
	inputsMockBaseURL := os.Getenv("MOCK_SERVER_URL_BATCH_MIXED_INPUTS")
	if inputsMockBaseURL == "" {
		inputsMockBaseURL = os.Getenv("MOCK_SERVER_URL") + "/fixtures/url_batch_mixed_inputs"
	}
	inputsJSON := strings.ReplaceAll(`[{"kind":"uri","uri":"$mock_url"},{"bytes":"QmF0Y2ggYnl0ZXMgY29udGVudA==","filename":"inline.txt","kind":"bytes","mime_type":"text/plain"}]`, "$mock_url", inputsMockBaseURL)
	var inputs []xberg.ExtractInput
	if err := json.Unmarshal([]byte(inputsJSON), &inputs); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	var config xberg.ExtractionConfig
	if err := json.Unmarshal([]byte(`{"url":{"mode":"document"}}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := xberg.ExtractBatch(inputs, config)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	assert.GreaterOrEqual(t, len(result.Results), 2, "expected at least 2 elements")
	if len(result.Results) > 0 {
		if !strings.Contains(string(result.Results[0].Content), `Batch URL document content`) {
			t.Errorf("expected to contain %s, got %v", `Batch URL document content`, result.Results[0].Content)
		}
	}
	if !strings.Contains(string(result.Results[1].Content), `Batch bytes content`) {
		t.Errorf("expected to contain %s, got %v", `Batch bytes content`, result.Results[1].Content)
	}
}

